  ('south', 'op', 96, 'OP', '南；南方', 'the direction opposite north', 'Warm wind came from the south.', '暖风从南方吹来。', '[{"w":"north","def":"north: 相关的动作或关系词","vs":"与 south 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"north\" / \"south\" 的替换练习"},{"w":"east","def":"east: 可帮助扩展句型的基础词","vs":"与 south 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"east\" / \"south\" 的替换练习"},{"w":"west","def":"west: 同一组 Basic English 操作词","vs":"与 south 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"west\" / \"south\" 的替换练习"}]'),
  ('east', 'op', 97, 'OP', '东；东方', 'the direction where the sun rises', 'The sun came up in the east.', '太阳从东方升起。', '[{"w":"south","def":"south: 相关的动作或关系词","vs":"与 east 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"south\" / \"east\" 的替换练习"},{"w":"west","def":"west: 可帮助扩展句型的基础词","vs":"与 east 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"west\" / \"east\" 的替换练习"},{"w":"please","def":"please: 同一组 Basic English 操作词","vs":"与 east 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"please\" / \"east\" 的替换练习"}]'),
  ('west', 'op', 98, 'OP', '西；西方', 'the direction where the sun sets', 'The road turns west after the bridge.', '过桥后，道路转向西边。', '[{"w":"east","def":"east: 相关的动作或关系词","vs":"与 west 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"east\" / \"west\" 的替换练习"},{"w":"please","def":"please: 可帮助扩展句型的基础词","vs":"与 west 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"please\" / \"west\" 的替换练习"},{"w":"yes","def":"yes: 同一组 Basic English 操作词","vs":"与 west 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"yes\" / \"west\" 的替换练习"}]'),
  ('please', 'op', 99, 'OP', '请；使高兴', 'used to make a request polite or to satisfy', 'Please put the cup on the table.', '请把杯子放在桌上。', '[{"w":"west","def":"west: 相关的动作或关系词","vs":"与 please 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"west\" / \"please\" 的替换练习"},{"w":"yes","def":"yes: 可帮助扩展句型的基础词","vs":"与 please 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"yes\" / \"please\" 的替换练习"}]'),
  ('yes', 'op', 100, 'OP', '是；对；表示同意', 'an affirmative answer or agreement', 'Yes, I will come after breakfast.', '是的，我早饭后会来。', '[{"w":"please","def":"please: 相关的动作或关系词","vs":"与 yes 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"please\" / \"yes\" 的替换练习"}]');
